const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;

function isComponent(type: string): boolean {
  return !(type in BASE_PREMIUMS);
}

function computeQuotePremium(items: Array<{ type: string }>): number {
  let basePremium = 0;

  const mainItems = items.filter((item) => !isComponent(item.type));
  for (const item of mainItems) {
    basePremium += BASE_PREMIUMS[item.type];
  }

  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    }
  }
  for (const [, count] of componentCounts) {
    if (count === 3) {
      basePremium += COMPONENT_BLOCK_PREMIUM;
    } else {
      basePremium += count * COMPONENT_PREMIUM;
    }
  }

  return Math.ceil(basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE);
}

export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Array<{ type: string }> }> }) {
  const results = scenario.steps.map((step) => ({
    premium: computeQuotePremium(step.items ?? []),
  }));
  return { results };
}

