const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const CURSED_SURCHARGE_RATE = 0.5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;

interface Item {
  type: string;
  cursed?: boolean;
}

function isComponent(type: string): boolean {
  return !(type in BASE_PREMIUMS);
}

function mainItemPremium(items: Item[]): number {
  return items
    .filter((item) => !isComponent(item.type))
    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
}

function componentPremium(items: Item[]): number {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  let total = 0;
  for (const [, count] of counts) {
    total += count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
  }
  return total;
}

function itemSurcharges(items: Item[]): number {
  return items
    .filter((item) => item.cursed)
    .reduce((sum, item) => {
      const base = BASE_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
      return sum + base * CURSED_SURCHARGE_RATE;
    }, 0);
}

function computeQuotePremium(items: Item[]): number {
  const basePremium = mainItemPremium(items) + componentPremium(items);
  const surcharges = itemSurcharges(items);
  return Math.ceil(basePremium + surcharges + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE);
}

export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Item[] }> }) {
  const results = scenario.steps.map((step) => ({
    premium: computeQuotePremium(step.items ?? []),
  }));
  return { results };
}

