const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

function isComponent(type: string): boolean {
  return !(type in BASE_PREMIUMS);
}

function mainItemPremium(items: Item[]): number {
  return items
    .filter((item) => !isComponent(item.type))
    .reduce((sum, item) => sum + itemBasePremium(item), 0);
}

function componentCounts(items: Item[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const item of items) {
    if (isComponent(item.type)) {
      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
    }
  }
  return counts;
}

function componentPremium(items: Item[]): number {
  return [...componentCounts(items).values()].reduce(
    (total, count) => total + (count === 3 ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM),
    0,
  );
}

function itemBasePremium(item: Item): number {
  return BASE_PREMIUMS[item.type] ?? COMPONENT_PREMIUM;
}

function singleItemSurcharge(item: Item): number {
  const base = itemBasePremium(item);
  return (item.cursed ? base * CURSED_SURCHARGE_RATE : 0)
    + ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
}

function itemSurcharges(items: Item[]): number {
  return items.reduce((sum, item) => sum + singleItemSurcharge(item), 0);
}

function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
  const basePremium = mainItemPremium(items) + componentPremium(items);
  const surcharges = itemSurcharges(items);
  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
  return Math.ceil(basePremium + surcharges + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
}

export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: Array<{ op: string; items?: Item[] }> }) {
  const results = scenario.steps.map((step, index) => {
    return { premium: computeQuotePremium(step.items ?? [], scenario.customer, index > 0) };
  });
  return { results };
}

import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums", () => {
    it("returns 5G processing fee for an empty item list", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [] }],
      });
      expect(result).toEqual({ results: [{ premium: 5 }] });
    });
    it("computes base premium for a single sword (100G + 10G first insurance + 5G fee = 115G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote",
            items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
          },
        ],
      });
      expect(result).toEqual({ results: [{ premium: 115 }] });
    });
    it("computes base premium for each main item type (amulet, staff, potion)", () => {
      const amulet = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
      });
      expect(amulet).toEqual({ results: [{ premium: 71 }] });

      const staff = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }] }],
      });
      expect(staff).toEqual({ results: [{ premium: 93 }] });

      const potion = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
      });
      expect(potion).toEqual({ results: [{ premium: 49 }] });
    });
    it("computes base premium for a single component (rune: 25G + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 33 }] });
    });
    it("computes base premium for 3 alike components using block discount (60G + 5G fee)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("does not apply block discount for 2 or 4 alike components", () => {
      const twoRunes = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
      });
      expect(twoRunes).toEqual({ results: [{ premium: 60 }] });

      const fourRunes = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
      });
      expect(fourRunes).toEqual({ results: [{ premium: 115 }] });
    });
    it("treats different component types as not alike (2 runes + 1 moonstone = 75G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
      });
      expect(result).toEqual({ results: [{ premium: 88 }] });
    });
    it("applies separate blocks for different component types (3 runes + 3 moonstones = 120G)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        }],
      });
      expect(result).toEqual({ results: [{ premium: 137 }] });
    });
  });

  describe("Quote — item-specific modifiers", () => {
    it("adds 50% cursed surcharge to the cursed item's base premium", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        }],
      });
      // 100 base + 50 curse (50% of 100) + 10 first insurance (10% of 100) + 5 fee = 165
      expect(result).toEqual({ results: [{ premium: 165 }] });
    });
    it("adds 30% high-enchantment surcharge for enchantment level >= 5", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
        }],
      });
      // 100 base + 30 enchantment (30% of 100) + 10 first insurance (10% of 100) + 5 fee = 145
      expect(result).toEqual({ results: [{ premium: 145 }] });
    });
    it("applies both cursed and high-enchantment surcharges to the same item", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
        }],
      });
      // 100 base + 50 curse + 30 enchantment + 10 first insurance + 5 fee = 195
      expect(result).toEqual({ results: [{ premium: 195 }] });
    });
    it("applies item-specific surcharges only to affected items in a multi-item policy", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: true },
            { type: "amulet", material: "silver", enchantment: 0, cursed: false },
          ],
        }],
      });
      // policy base: 100 + 60 = 160
      // item surcharges: 50 (curse on sword only, 50% of 100)
      // policy-wide: 16 (10% of 160)
      // fee: 5
      // total: 160 + 50 + 16 + 5 = 231
      expect(result).toEqual({ results: [{ premium: 231 }] });
    });
  });

  describe("Quote — policy-wide modifiers", () => {
    it("adds 10% first-insurance surcharge on every quote", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
        }],
      });
      // 60 base + 6 first insurance (10% of 60) + 5 fee = 71
      // Note: loyalty discount not yet implemented — this test just confirms first insurance is always present
      expect(result).toEqual({ results: [{ premium: 71 }] });
    });
    it("applies 20% loyalty discount for customers with >= 2 years", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 2 },
        steps: [{
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
        }],
      });
      // 100 base + 10 first insurance (10% of 100) - 20 loyalty (20% of 100) + 5 fee = 95
      expect(result).toEqual({ results: [{ premium: 95 }] });
    });
    it("applies 15% follow-up discount on second and subsequent quotes", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
          { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] },
        ],
      });
      // First quote: 100 + 10 + 5 = 115
      // Second quote: 100 + 10 - 15 (15% of 100) + 5 = 100
      expect(result).toEqual({ results: [{ premium: 115 }, { premium: 100 }] });
    });
    it.todo("stacks all policy-wide modifiers (loyalty + first insurance + follow-up)");
  });

  describe("Quote — rounding and integration", () => {
    it.todo("rounds final premium up in MHPCO's favor");
    it.todo("newcomer with cursed sword: premium is 165G");
    it.todo("long-standing customer second contract with cursed high-enchantment sword: premium is 160G");
  });

  describe("Quote — errors", () => {
    it.todo("rejects unknown item type with an error");
  });

  describe("Claim — standard reimbursement", () => {
    it.todo("pays full damage minus 100G deductible for a standard item");
    it.todo("applies deductible per damage entry when multiple items are damaged");
  });

  describe("Claim — special clauses", () => {
    it.todo("reimburses at 50% for items with enchantment >= 8, then deductible");
    it.todo("fully reimburses dragon-material items, then deductible");
    it.todo("applies 50% rule when item has both dragon material and enchantment >= 8");
  });

  describe("Claim — cap and exhaustion", () => {
    it.todo("caps total payout at 2x the insurance sum");
    it.todo("tracks remaining cap across multiple claims on the same policy");
  });

  describe("Claim — rounding", () => {
    it.todo("rounds payout down in MHPCO's favor");
  });

  describe("Claim — errors", () => {
    it.todo("rejects damage to an item not covered by the policy");
    it.todo("rejects more damage entries of a type than items insured");
    it.todo("rejects negative damage amounts");
  });
});

